import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.provider.Settings
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private val PREFS_NAME = "MyBiometricPrefs"
    private val KEY_AUTHENTICATED = "isAuthenticated"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        if (isAuthenticated()) {
            navigateToHomeScreen()
            return
        }

        setContentView(R.layout.activity_main) // Ensure you have this layout

        val loginWithBiometricsButton: Button = findViewById(R.id.loginWithBiometricsButton)
        val loginWithPasswordButton: Button = findViewById(R.id.loginWithPasswordButton)

        executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(applicationContext, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
                    // Fallback to password or show error message
                    if (errorCode == BiometricPrompt.ERROR_USER_CANCELED ||
                        errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                        // User chose to use password or cancelled, do nothing specific for now
                    } else if (errorCode == BiometricPrompt.ERROR_NO_BIOMETRICS ||
                        errorCode == BiometricPrompt.ERROR_HW_UNAVAILABLE ||
                        errorCode == BiometricPrompt.ERROR_UNSUPPORTED) {
                        Toast.makeText(applicationContext, "Biometric features not available or not enrolled. Please use password.", Toast.LENGTH_LONG).show()
                    }
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Toast.makeText(applicationContext, "Authentication succeeded!", Toast.LENGTH_SHORT).show()
                    setAuthenticated(true)
                    navigateToHomeScreen()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(applicationContext, "Authentication failed. Try again.", Toast.LENGTH_SHORT).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric login for MyApp")
            .setSubtitle("Log in using your fingerprint or face")
            .setNegativeButtonText("Use password instead")
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK or BiometricManager.Authenticators.DEVICE_CREDENTIAL) //DEVICE_CREDENTIAL for screen lock PIN/pattern/password fallback
            .build()

        loginWithBiometricsButton.setOnClickListener {
            checkBiometricSupportAndAuthenticate()
        }

        loginWithPasswordButton.setOnClickListener {
            Toast.makeText(this, "Navigating to password login...", Toast.LENGTH_SHORT).show()
            // In a real app, this would navigate to a password login screen
            // For now, let's just bypass
            setAuthenticated(true) // For demonstration, treat password login as successful
            navigateToHomeScreen()
        }
    }

    private fun checkBiometricSupportAndAuthenticate() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.DEVICE_CREDENTIAL)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                // All good, go ahead and authenticate
                biometricPrompt.authenticate(promptInfo)
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                Toast.makeText(this, "No biometric features available on this device.", Toast.LENGTH_LONG).show()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                Toast.makeText(this, "Biometric hardware is currently unavailable.", Toast.LENGTH_LONG).show()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                // Prompts the user to create credentials that the app accepts.
                Toast.makeText(this, "No biometrics enrolled. Please enroll biometrics in settings.", Toast.LENGTH_LONG).show()
                val enrollIntent = Intent(Settings.ACTION_BIOMETRIC_ENROLL).apply {
                    putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED, BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.DEVICE_CREDENTIAL)
                }
                startActivity(enrollIntent)
            }
            BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED -> {
                Toast.makeText(this, "Security update required for biometrics.", Toast.LENGTH_LONG).show()
            }
            BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED -> {
                Toast.makeText(this, "Biometric features are unsupported.", Toast.LENGTH_LONG).show()
            }
            else -> {
                Toast.makeText(this, "Unknown biometric error.", Toast.LENGTH_LONG).show()
            }
        }
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)
    }

    private fun setAuthenticated(isAuthenticated: Boolean) {
        with(sharedPreferences.edit()) {
            putBoolean(KEY_AUTHENTICATED, isAuthenticated)
            apply()
        }
    }

    private fun navigateToHomeScreen() {
        // In a real app, this would be your main app content activity
        val intent = Intent(this, HomeScreenActivity::class.java)
        startActivity(intent)
        finish() // Close login activity
    }
}

// Dummy HomeScreenActivity
class HomeScreenActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private val PREFS_NAME = "MyBiometricPrefs"
    private val KEY_AUTHENTICATED = "isAuthenticated"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home_screen) // Ensure you have this layout
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        val logoutButton: Button = findViewById(R.id.logoutButton)
        logoutButton.setOnClickListener {
            setAuthenticated(false)
            val intent = Intent(this, MainActivity::class.java)
            startActivity(intent)
            finish()
        }
    }

    private fun setAuthenticated(isAuthenticated: Boolean) {
        with(sharedPreferences.edit()) {
            putBoolean(KEY_AUTHENTICATED, isAuthenticated)
            apply()
        }
    }
}

